import React, { useState, useEffect, useCallback } from 'react';
import { Search, User, Cpu, Phone, MapPin, ChevronRight, X, Loader } from 'lucide-react';
import { getVillager, getSensors } from '../../api';

function debounce(fn, ms) {
  let t;
  return (...args) => { clearTimeout(t); t = setTimeout(() => fn(...args), ms); };
}

export default function VillagerSearch({ villagers, panchayatId, onVillagerClick }) {
  const [query, setQuery] = useState('');
  const [filtered, setFiltered] = useState(villagers);
  const [selected, setSelected] = useState(null);
  const [sensors, setSensors] = useState([]);
  const [loadingDetail, setLoadingDetail] = useState(false);

  useEffect(() => {
    if (!query.trim()) {
      setFiltered(villagers);
    } else {
      setFiltered(villagers.filter(v =>
        v.name.toLowerCase().includes(query.toLowerCase())
      ));
    }
  }, [query, villagers]);

  const openVillager = async (v) => {
    setSelected(v);
    setLoadingDetail(true);
    try {
      const detail = await getVillager(v.id);
      setSensors(detail.sensors || []);
    } catch (err) {
      setSensors([]);
    } finally {
      setLoadingDetail(false);
    }
  };

  const close = () => { setSelected(null); setSensors([]); };

  return (
    <div className="card h-full flex flex-col">
      <div className="p-4 border-b border-gray-800">
        <div className="flex items-center gap-2 mb-3">
          <User className="w-4 h-4 text-purple-400" />
          <h2 className="text-sm font-semibold text-gray-100">Search Villagers</h2>
          <span className="ml-auto text-xs text-gray-500 bg-gray-800 px-2 py-0.5 rounded-full">{villagers.length} total</span>
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
          <input
            type="text"
            value={query}
            onChange={e => setQuery(e.target.value)}
            className="input-field pl-9 pr-8"
            placeholder="Search by name..."
          />
          {query && (
            <button onClick={() => setQuery('')} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-600 hover:text-gray-400">
              <X className="w-3.5 h-3.5" />
            </button>
          )}
        </div>
      </div>

      {!selected ? (
        <div className="flex-1 overflow-y-auto">
          {filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-32 text-gray-600">
              <User className="w-8 h-8 mb-2 opacity-30" />
              <p className="text-sm">{query ? 'No villagers found' : 'No villagers added yet'}</p>
            </div>
          ) : (
            filtered.map(v => (
              <button
                key={v.id}
                onClick={() => openVillager(v)}
                className="w-full flex items-center gap-3 px-4 py-3 hover:bg-gray-800/60 transition-colors border-b border-gray-800/50 last:border-0 text-left group"
              >
                <div className="w-8 h-8 rounded-full bg-purple-900/50 border border-purple-700/40 flex items-center justify-center flex-shrink-0 text-purple-300 font-bold text-sm">
                  {v.name.charAt(0).toUpperCase()}
                </div>
                <div className="min-w-0 flex-1">
                  <div className="text-sm font-medium text-gray-100">{v.name}</div>
                  <div className="text-xs text-gray-500 flex items-center gap-2 mt-0.5">
                    <span className="flex items-center gap-1"><Cpu className="w-3 h-3" />{v.sensor_count || 0} sensors</span>
                    {v.phone && <span className="flex items-center gap-1"><Phone className="w-3 h-3" />{v.phone}</span>}
                  </div>
                </div>
                <ChevronRight className="w-4 h-4 text-gray-600 group-hover:text-gray-400" />
              </button>
            ))
          )}
        </div>
      ) : (
        <div className="flex-1 overflow-y-auto fade-in-up">
          {/* Villager detail */}
          <div className="p-4 border-b border-gray-800">
            <div className="flex items-center gap-3">
              <button onClick={close} className="p-1 text-gray-500 hover:text-white rounded">
                <X className="w-4 h-4" />
              </button>
              <div className="w-10 h-10 rounded-full bg-purple-900/50 border border-purple-700/40 flex items-center justify-center text-purple-300 font-bold text-lg">
                {selected.name.charAt(0).toUpperCase()}
              </div>
              <div>
                <div className="text-sm font-semibold text-white">{selected.name}</div>
                {selected.phone && <div className="text-xs text-gray-500 flex items-center gap-1"><Phone className="w-3 h-3" />{selected.phone}</div>}
              </div>
            </div>
            {selected.address && (
              <div className="mt-2 flex items-start gap-1.5 text-xs text-gray-500">
                <MapPin className="w-3 h-3 mt-0.5 flex-shrink-0" />
                <span>{selected.address}</span>
              </div>
            )}
          </div>

          <div className="p-4">
            <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3 flex items-center gap-1.5">
              <Cpu className="w-3.5 h-3.5" /> Sensors ({sensors.length})
            </div>
            {loadingDetail ? (
              <div className="flex items-center justify-center py-6 text-gray-500">
                <Loader className="w-5 h-5 animate-spin mr-2" /> Loading...
              </div>
            ) : sensors.length === 0 ? (
              <p className="text-xs text-gray-600 text-center py-4">No sensors assigned</p>
            ) : (
              <div className="space-y-2">
                {sensors.map(s => (
                  <div key={s.id} className="flex items-center gap-3 bg-gray-800/60 rounded-lg px-3 py-2.5">
                    <div className="w-1.5 h-1.5 rounded-full flex-shrink-0 mt-0.5" style={{
                      backgroundColor: s.status === 'active' ? '#22c55e' : s.status === 'faulty' ? '#ef4444' : '#6b7280'
                    }} />
                    <div className="min-w-0 flex-1">
                      <div className="text-xs font-mono font-medium text-gray-200">{s.id}</div>
                      <div className="text-xs text-gray-500">{s.name || s.type}</div>
                    </div>
                    <span className={`text-xs px-1.5 py-0.5 rounded font-medium ${
                      s.status === 'active' ? 'text-green-400 bg-green-900/30' :
                      s.status === 'faulty' ? 'text-red-400 bg-red-900/30' :
                      'text-gray-400 bg-gray-800'}`}>
                      {s.type}
                    </span>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
